window.addEventListener("pageshow",function(event){if(event.persisted){if($(".page-section").hasClass("hide")){$(".page-section").removeClass("hide");$(".button").removeClass("active");$(".all").addClass("active")}}else{if($(".page-section").hasClass("hide")){$(".page-section").removeClass("hide");$(".button").removeClass("active");$(".all").addClass("active")}}});var checkClass=function(){if($(".page-section").hasClass("hide")){$(".page-section").removeClass("hide")}};$(".all").click(function(){checkClass()});$(".adios_al_efectivo").click(function(){checkClass();$(".page-section:not(.adios_al_efectivo)").toggleClass("hide")});$(".inclusion_financiera").click(function(){checkClass();$(".page-section:not(.inclusion_financiera)").toggleClass("hide")});$(".button").click(function(){if($(".page-section").children(":visible").length==0){Swal.fire({title:"Estamos trabajando!",text:"¡Muy pronto tendremos novedades!",imageUrl:"https://i.gifer.com/Ao.gif",imageWidth:400,imageHeight:400,imageAlt:"Yape articulos"})}$(".button").removeClass("active");$(this).addClass("active")});